#!/usr/bin/env python3
"""
Generate LaTeX table fragments from reproduce output CSVs.

Usage:
  python reproduce_results/gen_paper_tables.py

Output: paper/tables_generated.tex (fragments to copy into main.tex)
"""

import csv
from pathlib import Path

OUT = Path(__file__).parent.parent / "paper" / "tables_generated.tex"


def read_csv(path):
    if not path.exists():
        return []
    with open(path, encoding="utf-8") as f:
        return list(csv.DictReader(f))


def main():
    out_dir = Path(__file__).parent / "output"
    lines = [
        "% Auto-generated by reproduce_results/gen_paper_tables.py",
        "% Copy relevant fragments into main.tex as needed.",
        "",
    ]

    # Calibration
    rows = read_csv(out_dir / "tab_calibration.csv")
    if rows:
        lines.append("% --- tab_calibration ---")
        lines.append("\\begin{tabular}{lccc}")
        lines.append("\\toprule")
        lines.append("\\textbf{Ability Level} & \\textbf{Calibration Accuracy (\\%)} & \\textbf{Avg. Convergence (questions)} & \\textbf{Stability Rate (\\%)} \\\\")
        lines.append("\\midrule")
        for r in rows:
            al = r.get("Ability Level", "")
            ca = r.get("Calibration Accuracy (%)", "---")
            conv = r.get("Avg. Convergence (questions)", "---")
            stab = r.get("Stability Rate (%)", "---")
            lines.append(f"{al} & {ca} & {conv} & {stab} \\\\")
        lines.append("\\bottomrule")
        lines.append("\\end{tabular}")
        lines.append("")

    # Selection
    rows = read_csv(out_dir / "tab_selection.csv")
    if rows:
        lines.append("% --- tab_selection ---")
        lines.append("\\begin{tabular}{lcccc}")
        lines.append("\\toprule")
        lines.append("\\textbf{Strategy} & \\textbf{Gap Targeting (\\%)} & \\textbf{Coverage (\\%)} & \\textbf{Personalization (\\%)} & \\textbf{Avg. Relevance Score} \\\\")
        lines.append("\\midrule")
        for r in rows:
            s = r.get("Strategy", "")
            gt = r.get("Gap Targeting (%)", "---")
            cov = r.get("Coverage (%)", "---")
            pers = r.get("Personalization (%)", "---")
            rel = r.get("Avg. Relevance Score", "---")
            lines.append(f"{s} & {gt} & {cov} & {pers} & {rel} \\\\")
        lines.append("\\bottomrule")
        lines.append("\\end{tabular}")
        lines.append("")

    # Evaluation
    rows = read_csv(out_dir / "tab_evaluation.csv")
    if rows:
        lines.append("% --- tab_evaluation ---")
        lines.append("\\begin{tabular}{lc}")
        lines.append("\\toprule")
        lines.append("\\textbf{Evaluation Dimension} & \\textbf{Exact Agreement (\\%)} \\\\")
        lines.append("\\midrule")
        for r in rows:
            dim = r.get("Dimension", "")
            ag = r.get("Exact Agreement (%)", "---")
            lines.append(f"{dim} & {ag} \\\\")
        lines.append("\\bottomrule")
        lines.append("\\end{tabular}")
        lines.append("")

    # System performance
    rows = read_csv(out_dir / "tab_system_performance.csv")
    if rows:
        lines.append("% --- tab_system_performance ---")
        for r in rows:
            m = r.get("Metric", "")
            v = r.get("Value", "---")
            ci = r.get("95% CI", "---")
            lines.append(f"% {m}: {v} (CI: {ci})")
        lines.append("")

    # Interview outcomes
    rows = read_csv(out_dir / "tab_interview_outcomes.csv")
    if rows:
        lines.append("% --- tab_interview_outcomes ---")
        lines.append("\\begin{tabular}{lccc}")
        lines.append("\\toprule")
        lines.append("\\textbf{Termination Type} & \\textbf{Count} & \\textbf{Percentage} & \\textbf{Avg. Rounds} \\\\")
        lines.append("\\midrule")
        for r in rows:
            tt = r.get("Termination Type", "")
            c = r.get("Count", "")
            p = r.get("Percentage", "")
            ar = r.get("Avg. Rounds", "")
            lines.append(f"{tt} & {c} & {p} & {ar} \\\\")
        lines.append("\\bottomrule")
        lines.append("\\end{tabular}")
        lines.append("")

    OUT.parent.mkdir(parents=True, exist_ok=True)
    OUT.write_text("\n".join(lines), encoding="utf-8")
    print(f"Generated {OUT}")


if __name__ == "__main__":
    main()
